var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"오래 전, 아홉 대륙을 아우르는 전설이 있었다.","JPN":"大昔、九つの大陸をまとめる伝説があった。","ENG":"A long time ago, there was a legend that was told across the nine continents.","TWN":"這無趣的傳說是這麼說的，很久很久以前，據說9個大陸是合在一起的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"하늘의 선택을 받은 구원자가 나타나 모두를 괴로움에서 구원하리라는, 시시한 전설이.","JPN":"天から選ばれし救世主が現れ、みんなを苦痛から救うというくだらない伝説が。","ENG":"A bland legend that spoke of the arrival of the Savior, appointed by the heavens, who would save everyone from suffering.","TWN":"天選之救贖者出現，將在水深火熱之中的人救贖出來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"그는 어두운 시대에 희망을 추구하던 여인 앞에 홀연히 나타나 성녀를 찾아왔다고 하지만…","JPN":"彼は暗き時代の中で希望を求めていた女性の前に忽然と現れ、聖女を探しにきたという。だが……","ENG":"It is said that he would reveal himself to a woman praying for hope in a dark age and claim that he came searching for the Saintess, but...","TWN":"女孩則是在黑暗的世代中尋求一絲希望，有一天，救贖者突然出現在女孩面前，說是來找聖女的…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"당시 노예였던 내게, 그것은 너무나도 먼 세계의 이야기였다.","JPN":"当時奴隷だった私にとって、それはあまりにも遠い世界の話だった。","ENG":"It was such a distant story, as I was a slave at the time.","TWN":"但對於當時身為奴隸的我而言，這是一個遙不可及的故事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"추, 춤이란 건 생각보다 어렵구나.","JPN":"だ、ダンスって思ったより難しいんだね。","ENG":"D-dancing is harder than I thought.","TWN":"跳舞比想像中難呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L10_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안. 내가 권유해 놓고 모양새가 영 아니네.","JPN":"ごめん。自分で誘っておいて下手すぎるね。","ENG":"I'm sorry. I offered, but I'm not doing well at all.","TWN":"對不起，是我邀請你的，結果我也不太會跳。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"괜찮습니다. 저도 이런 건 익숙하지 않으니까요.","JPN":"大丈夫です。私もこういうことには慣れていませんから。","ENG":"It is okay. I'm not used to this either.","TWN":"沒關係，我也不習慣跳舞。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_PIN","text":{"KOREA":"지금은 우선… 천천히 제게 맞춰주세요.","JPN":"今はとりあえず……ゆっくりと私に合わせてください。","ENG":"For now... please follow my lead.","TWN":"現在…先慢慢配合我的步伐。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"신기한 기분이다.","JPN":"不思議な気分だ。","ENG":"It's an amazing feeling.","TWN":"真是奇妙的感覺。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"먼 동화 속 이야기인 줄만 알았던 사람이, 지금은 이렇게나 가까이에 있다.","JPN":"遠いおとぎ話のことだと思っていた人が、今はこんなにも近くにいる。","ENG":"The person who I thought was just a myth is standing right in front of me.","TWN":"原以為是如童話故事般遙不可及的人，現在卻如此靠近。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HOLY_MEMORIAL_NPC_PIN","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이렇게… 하는 건가?","JPN":"こう……かな？","ENG":"Is this... how you do it?","TWN":"是…這樣嗎？"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"네, 잘하시네요. 역시 구원자님이세요.","JPN":"はい、お上手です。さすが救世主様ですね。","ENG":"Yes, you're doing great, just as I thought you would.","TWN":"沒錯，您跳得很好，不愧是救贖者大人。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"첫 만남 당시, 미처 붙잡지 못했던 손이.","JPN":"出会った頃は握ることもできなかった手が。","ENG":"The hand I couldn't get myself to hold when we first met.","TWN":"第一次見面時未能抓住的手，"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"당신의 맥박이, 숨결이. 지금은 뚜렷하게 느껴진다.","JPN":"あなたの脈が、息が。今ははっきりと感じられる。","ENG":"Your heartbeat. Your breath. Everything is so vivid now.","TWN":"你的脈搏，你的呼吸，我現在都能夠清楚感受到。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그러고 보니 말이야.","JPN":"そういえばさ。","ENG":"By the way.","TWN":"說起來，露可蕾西亞，"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아는, 성녀가 된 이후로는 내게 격식을 갖추고 있지?","JPN":"ルクレシアは、聖女になってからは僕に礼儀正しいよね？","ENG":"Lucrecia, you've been acting more formal towards me since you became the Saintess, right?","TWN":"自從你成為聖女後，有刻意對我保持禮儀吧？"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"예전에는 철이 없었으니까요.","JPN":"昔は世間知らずでしたから。","ENG":"I didn't know better before.","TWN":"因為以前的我很不知輕重。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님도… 그때는 어떤 분인지 몰랐고요.","JPN":"救世主様も……あの時はどんな方かも知らなかったですし。","ENG":"I didn't know... what you were like, either.","TWN":"當時…我還不知道您的身分。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"딱히 나무라는 게 아니야.","JPN":"別に咎めるつもりで言ったんじゃないよ。","ENG":"I'm not trying to scold you or anything.","TWN":"我不是在責備你。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그냥, 예전처럼 말해도 상관없다는 뜻이었어.","JPN":"ただ、昔みたいに話してくれても構わないっていう意味だったんだ。","ENG":"I just wanted to say that you can talk to me like you did before.","TWN":"我只是想說，你可以像以前那樣對我說話。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"난 그런 거 별로 신경 안 쓰니까.","JPN":"僕はそんなことあまり気にしないから。","ENG":"I don't really mind that kind of stuff.","TWN":"我不在意這些。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"안 됩니다. 성녀인 제가 구원자님을 불경하게 대할 순 없어요.","JPN":"いいえ。聖女である私が、救世主様に不敬な態度を取るわけにはいきません。","ENG":"I will not abide by that. As Saintess, I cannot talk to you in a blasphemous manner.","TWN":"不行，聖女怎麼可以對救贖者大人不敬。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"부, 불경하기 까지야….","JPN":"ふ、不敬ってことは……","ENG":"B-blasphemous seems like a stretch...","TWN":"哪有什麼敬不敬…"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님은… 제 예전 모습이 더 좋으신가요?","JPN":"救世主様は……私の昔の姿の方を好まれるのですか？","ENG":"Do you... prefer the old me, Savior?","TWN":"救贖者大人…您比較喜歡以前的我嗎？"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"설마. 어느 모습이든 루크레시아는 루크레시아인걸.","JPN":"まさか。どんな姿でも、ルクレシアはルクレシアだよ。","ENG":"Not at all. You're you, no matter your appearance.","TWN":"不是，不管是以前的你，還是現在的你，對我來說，你就是你。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그래도 가끔씩은 예전이랑 많이 달라졌다는 생각을 하곤 해.","JPN":"でもたまに、昔とはずいぶん変わったなって思うんだ。","ENG":"But sometimes, I do think you look a lot different than how you did before.","TWN":"只是有時會覺得你改變許多。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아도 여자애니까. 잘 보이고 싶은 사람이라도 있는 걸까?","JPN":"ルクレシアも女の子だからね。よく見られたい人でもいるのかな？","ENG":"I guess you are a woman after all. Is there someone you're trying to impress?","TWN":"你畢竟也是個女孩子，有想要取悅的人嗎？"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh.*","TWN":"……哀哀。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_HOLY_IN_TRAILER_1"},{"id":"L45_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"바-보.","JPN":"ばーか。","ENG":"You dummy.","TWN":"傻瓜。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_HOLY_IN_TRAILER_2"},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"응? 뭐라 했어, 루크레시아?","JPN":"うん？　何か言った？　ルクレシア。","ENG":"Hmm? What did you say, Lucrecia?","TWN":"嗯？你說什麼？"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아뇨. 아무것도 아니에요.","JPN":"いいえ、何でもありません。","ENG":"No. Never mind.","TWN":"沒有，沒什麼。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_HOLY_IN_TRAILER_3"},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"여기서부터는 조금 어려운 부분이니까, 제 움직임을 잘 따라와 주세요.","JPN":"ここからは少し難しくなりますから、私の動きにしっかり付いてきてください。","ENG":"This is where it gets tricky, so please follow my movement.","TWN":"接下來會比較難，請跟上我的動作。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_HOLY_IN_TRAILER_4"},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"떨어지지 않도록.","JPN":"離れずに。","ENG":"Be careful not to fall.","TWN":"不要落拍。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_HOLY_IN_TRAILER_5"},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"지금보다 더 가까이 붙어서요.","JPN":"今よりもさらに密着してください。","ENG":"Get closer to me.","TWN":"再靠近一點。"},"stage":{"bg":"GLOBAL1ST_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_HOLY_IN_TRAILER_6"}]`);export{e as default};